export const shouldClearScopedChartSelection = ({ activeChartId, chartId, dismissRevision, hasSelection, lastDismissRevision }) => {
    if (!hasSelection) {
        return false;
    }
    if (dismissRevision !== lastDismissRevision) {
        return true;
    }
    return activeChartId !== undefined && activeChartId !== chartId;
};
export const getScopedChartSelectionClearReason = ({ activeChartId, chartId, dismissRevision, lastDismissRevision }) => {
    if (dismissRevision !== lastDismissRevision) {
        return "programmatic";
    }
    if (activeChartId !== undefined && activeChartId !== chartId) {
        return "scopeChange";
    }
    return undefined;
};
